import os
import shutil
import psutil

def is_file_in_use(file_path):
    """Check if a file is in use by any running process."""
    for proc in psutil.process_iter(['pid', 'name']):
        try:
            if proc.info['pid'] == os.getpid():
                # If the process is the one that opened the file, return True
                return True
        except (psutil.NoSuchProcess, psutil.AccessDenied, psutil.ZombieProcess):
            pass
    return False

def remove_temp_files(directory):
    """Recursively remove files with a.tmp extension from the given directory."""
    for root, dirs, files in os.walk(directory):
        for file in files:
            if file.endswith('.tmp'):
                file_path = os.path.join(root, file)
                if not is_file_in_use(file_path):
                    try:
                        os.remove(file_path)
                        print(f"Removed {file_path}")
                    except OSError as e:
                        print(f"Error removing {file_path}: {e}")

if __name__ == "__main__":
    user_home_dir = '/home/user'
    remove_temp_files(user_home_dir)
